PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?player ?playerLabel (COUNT(*) AS ?count)
WHERE {
  ?player wdt:P166 wd:Q222047.
  OPTIONAL { ?player rdfs:label ?playerLabel . FILTER (LANG(?playerLabel) = "en") }
}
GROUP BY ?player ?playerLabel
ORDER BY DESC(?count)
LIMIT 1

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?winner ?winnerLabel (COUNT(*) AS ?count)
WHERE {
  wd:Q222047 wdt:P357 ?winner.
  OPTIONAL { ?winner rdfs:label ?winnerLabel . FILTER (LANG(?winnerLabel) = "en") }
}
GROUP BY ?winner ?winnerLabel
ORDER BY DESC(?count)
LIMIT 1
